<?php require __DIR__.'/../includes/bootstrap.php';if(!booths_schema_ready()){app_header('Booths');?><section class="form-card"><h1>Booths are not installed</h1><?php if((user()['role']??'')==='admin'):?><a class="button primary" href="../upgrade-booths-marketplace.php">Install Version 5</a><?php endif?></section><?php app_footer();exit;}$q=trim($_GET['q']??'');$sql="SELECT b.*,(SELECT COUNT(*) FROM booth_products p WHERE p.booth_id=b.id AND p.status='active') product_count FROM booths b WHERE b.status='approved'";$args=[];if($q!==''){$sql.=' AND (b.name LIKE ? OR b.description LIKE ?)';$args=['%'.$q.'%','%'.$q.'%'];}$sql.=' ORDER BY b.is_featured DESC,b.name';$s=db()->prepare($sql);$s->execute($args);$booths=$s->fetchAll();app_header('Booths');?>
<section class="dashboard-hero"><p class="eyebrow">VIRTUAL EXHIBIT HALL</p><h1>Convention Booths</h1><p>Meet creators, companies, and brands—and shop their convention tables.</p><form class="hero-search booth-search"><input name="q" value="<?=e($q)?>" placeholder="Search booths"><button>Search</button></form><?php if(user()):?><p><a class="button primary" href="create.php">Open a Booth</a> <a class="button ghost" href="dashboard.php">My Booths</a> <a class="button ghost" href="../cart.php">Cart (<?=cart_count()?>)</a></p><?php endif?></section>
<section class="booth-directory-grid"><?php foreach($booths as $b):?><article class="booth-directory-card"><?php if($b['banner_path']):?><img class="booth-card-banner" src="<?=e(base_url($b['banner_path']))?>" alt=""><?php endif?><div class="booth-card-body"><?php if($b['logo_path']):?><img class="booth-card-logo" src="<?=e(base_url($b['logo_path']))?>" alt=""><?php endif?><p class="eyebrow"><?=$b['is_featured']?'FEATURED BOOTH':'EXHIBITOR'?></p><h2><a href="view.php?slug=<?=urlencode($b['slug'])?>"><?=e($b['name'])?></a></h2><p><?=e($b['tagline']?:mb_strimwidth((string)$b['description'],0,130,'…'))?></p><span class="pill"><?=(int)$b['product_count']?> products</span></div></article><?php endforeach?><?php if(!$booths):?><div class="empty-state"><h2>No booths found</h2><p>The exhibit hall is waiting for its first vendors.</p></div><?php endif?></section><?php app_footer();